     1→import { Injectable, Logger } from '@nestjs/common';
     2→import { InjectDataSource } from '@nestjs/typeorm';
     3→import { DataSource } from 'typeorm';
     4→import Stripe from 'stripe';
     5→
     6→import { WalletEntity } from '@/db';
     7→import { env } from '@/env';
     8→
     9→/**
    10→ * Base Stripe service providing SDK initialization and core Stripe operations.
    11→ * Handles Stripe client lifecycle and common Stripe API interactions.
    12→ */
    13→@Injectable()
    14→export class StripeService {
    15→  private readonly logger = new Logger(StripeService.name);
    16→  private readonly stripe: Stripe;
    17→
    18→  constructor(@InjectDataSource() private readonly dataSource: DataSource) {
    19→    if (!env.STRIPE_SECRET_KEY) {
    20→      throw new Error('STRIPE_SECRET_KEY is not configured');
    21→    }
    22→
    23→    this.stripe = new Stripe(env.STRIPE_SECRET_KEY, {
    24→      typescript: true,
    25→    });
    26→
    27→    this.logger.log('Stripe SDK initialized');
    28→  }
    29→
    30→  /**
    31→   * Get the Stripe SDK client instance.
    32→   * Use this to access any Stripe API not wrapped by helper methods.
    33→   */
    34→  getClient(): Stripe {
    35→    return this.stripe;
    36→  }
    37→
    38→  /**
    39→   * Get or create Stripe Customer ID for a user.
    40→   * Checks wallet for existing customer ID to avoid creating duplicate customers.
    41→   *
    42→   * @param userId - Internal user ID
    43→   * @param email - User email (optional, for Stripe dashboard display)
    44→   * @param name - User name (optional, for Stripe dashboard display)
    45→   * @returns Stripe Customer ID
    46→   */
    47→  async getOrCreateCustomer({
    48→    userId,
    49→    email,
    50→    name,
    51→  }: {
    52→    userId: string;
    53→    email?: string;
    54→    name?: string;
    55→  }): Promise<string> {
    56→    const walletRepository = this.dataSource.getRepository(WalletEntity);
    57→
    58→    // Check if user's wallet already has a Stripe customer ID
    59→    const wallet = await walletRepository.findOne({
    60→      where: { userId },
    61→      select: ['id', 'stripeCustomerId'],
    62→    });
    63→
    64→    if (!wallet) {
    65→      throw new Error(`Wallet not found for user ${userId}`);
    66→    }
    67→
    68→    // Return existing customer ID if present
    69→    if (wallet.stripeCustomerId) {
    70→      this.logger.log(
    71→        `Reusing existing Stripe customer ${wallet.stripeCustomerId} for user ${userId}`,
    72→      );
    73→
    74→      return wallet.stripeCustomerId;
    75→    }
    76→
    77→    // No existing customer, create new one
    78→    const customer = await this.stripe.customers.create({
    79→      metadata: { userId },
    80→      email,
    81→      name,
    82→    });
    83→
    84→    // Store customer ID in wallet
    85→    await walletRepository.update(
    86→      { id: wallet.id },
    87→      { stripeCustomerId: customer.id },
    88→    );
    89→
    90→    this.logger.log(
    91→      `Created new Stripe customer: ${customer.id} for user: ${userId}`,
    92→    );
    93→
    94→    return customer.id;
    95→  }
    96→
    97→  /**
    98→   * Create a SetupIntent for tokenizing payment methods.
    99→   * Used to save cards/bank accounts without charging them.
   100→   *
   101→   * @param customerId - Stripe Customer ID
   102→   * @returns SetupIntent with client_secret for frontend
   103→   */
   104→  async createSetupIntent(customerId: string): Promise<Stripe.SetupIntent> {
   105→    const setupIntent = await this.stripe.setupIntents.create({
   106→      customer: customerId,
   107→      payment_method_types: ['card', 'us_bank_account'],
   108→    });
   109→
   110→    this.logger.log(
   111→      `Created SetupIntent: ${setupIntent.id} for customer: ${customerId}`,
   112→    );
   113→
   114→    return setupIntent;
   115→  }
   116→
   117→  /**
   118→   * Retrieve PaymentMethod details from Stripe.
   119→   *
   120→   * @param paymentMethodId - Stripe PaymentMethod ID
   121→   * @returns PaymentMethod object with card/bank details
   122→   */
   123→  async retrievePaymentMethod(
   124→    paymentMethodId: string,
   125→  ): Promise<Stripe.PaymentMethod> {
   126→    return this.stripe.paymentMethods.retrieve(paymentMethodId);
   127→  }
   128→
   129→  /**
   130→   * Attach a PaymentMethod to a Customer.
   131→   * Required before using a payment method for payments.
   132→   *
   133→   * @param paymentMethodId - Stripe PaymentMethod ID
   134→   * @param customerId - Stripe Customer ID
   135→   * @returns Updated PaymentMethod
   136→   */
   137→  async attachPaymentMethodToCustomer(
   138→    paymentMethodId: string,
   139→    customerId: string,
   140→  ): Promise<Stripe.PaymentMethod> {
   141→    const paymentMethod = await this.stripe.paymentMethods.attach(
   142→      paymentMethodId,
   143→      {
   144→        customer: customerId,
   145→      },
   146→    );
   147→
   148→    this.logger.log(
   149→      `Attached PaymentMethod: ${paymentMethodId} to customer: ${customerId}`,
   150→    );
   151→
   152→    return paymentMethod;
   153→  }
   154→
   155→  /**
   156→   * Detach a PaymentMethod from a Customer.
   157→   * Called when user removes a saved payment method.
   158→   *
   159→   * @param paymentMethodId - Stripe PaymentMethod ID
   160→   * @returns Updated PaymentMethod
   161→   */
   162→  async detachPaymentMethod(
   163→    paymentMethodId: string,
   164→  ): Promise<Stripe.PaymentMethod> {
   165→    const paymentMethod =
   166→      await this.stripe.paymentMethods.detach(paymentMethodId);
   167→
   168→    this.logger.log(`Detached PaymentMethod: ${paymentMethodId}`);
   169→
   170→    return paymentMethod;
   171→  }
   172→
   173→  /**
   174→   * Verify webhook signature to ensure the webhook came from Stripe.
   175→   *
   176→   * @param payload - Raw request body (Buffer or string)
   177→   * @param signature - stripe-signature header value
   178→   * @param secret - Webhook secret from Stripe Dashboard
   179→   * @returns Verified Stripe Event
   180→   * @throws Error if signature verification fails
   181→   */
   182→  constructWebhookEvent(
   183→    payload: string | Buffer,
   184→    signature: string,
   185→    secret: string,
   186→  ): Stripe.Event {
   187→    return this.stripe.webhooks.constructEvent(payload, signature, secret);
   188→  }
   189→}
