     1→import { Injectable, Logger } from '@nestjs/common';
     2→import { TransactionHost } from '@nestjs-cls/transactional';
     3→import Stripe from 'stripe';
     4→
     5→import { StripeEventEntity } from '@/db';
     6→import { TransactionalAdapterTypeOrm } from '@/modules/global';
     7→
     8→/**
     9→ * Service for handling Stripe webhook events with idempotency.
    10→ * Stores events in database to prevent duplicate processing.
    11→ */
    12→@Injectable()
    13→export class StripeWebhookService {
    14→  private readonly logger = new Logger(StripeWebhookService.name);
    15→
    16→  constructor(
    17→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    18→  ) {}
    19→
    20→  /**
    21→   * Store a Stripe webhook event in the database for idempotency.
    22→   * Returns true if this is a new event, false if already processed.
    23→   *
    24→   * @param event - Stripe Event object
    25→   * @returns true if event is new (should be processed), false if already seen
    26→   */
    27→  async storeEvent(event: Stripe.Event): Promise<boolean> {
    28→    return this.txHost.withTransaction(async () => {
    29→      const repository = this.txHost.tx.getRepository(StripeEventEntity);
    30→
    31→      // Check if event already exists
    32→      const existingEvent = await repository.findOne({
    33→        where: { stripeEventId: event.id },
    34→      });
    35→
    36→      if (existingEvent) {
    37→        this.logger.log(
    38→          `Event ${event.id} already processed at ${existingEvent.processedAt?.toISOString() || 'unknown'}`,
    39→        );
    40→
    41→        return false; // Already processed
    42→      }
    43→
    44→      // Store new event
    45→      await repository.save({
    46→        stripeEventId: event.id,
    47→        eventType: event.type,
    48→        payload: event as unknown as Record<string, any>,
    49→        apiVersion: event.api_version || null,
    50→        processedAt: null, // Will be updated after successful processing
    51→      });
    52→
    53→      this.logger.log(`Stored new webhook event: ${event.id} (${event.type})`);
    54→      return true; // New event, should be processed
    55→    });
    56→  }
    57→
    58→  /**
    59→   * Mark a webhook event as successfully processed.
    60→   *
    61→   * @param eventId - Stripe event ID
    62→   */
    63→  async markEventProcessed(eventId: string): Promise<void> {
    64→    return this.txHost.withTransaction(async () => {
    65→      const repository = this.txHost.tx.getRepository(StripeEventEntity);
    66→
    67→      await repository.update(
    68→        { stripeEventId: eventId },
    69→        { processedAt: new Date() },
    70→      );
    71→
    72→      this.logger.log(`Marked event as processed: ${eventId}`);
    73→    });
    74→  }
    75→
    76→  /**
    77→   * Get a stored webhook event by Stripe event ID.
    78→   *
    79→   * @param eventId - Stripe event ID
    80→   * @returns Stored event entity or null if not found
    81→   */
    82→  async getEvent(eventId: string): Promise<StripeEventEntity | null> {
    83→    const repository = this.txHost.tx.getRepository(StripeEventEntity);
    84→    return repository.findOne({ where: { stripeEventId: eventId } });
    85→  }
    86→}
