    10→import { PaymentEntity, PaymentStatus } from '@/db';
    11→import { env } from '@/env';
    12→import { TransactionalAdapterTypeOrm } from '@/modules/global';
    13→
    14→import { StripeService } from './stripe.service';
    15→
    16→/**
    17→ * Service for creating and managing Stripe Checkout Sessions.
    18→ * Handles payment flow from payment creation through Stripe checkout completion.
    19→ */
    20→@Injectable()
    21→export class StripeCheckoutService {
    22→  private readonly logger = new Logger(StripeCheckoutService.name);
    23→
    24→  constructor(
    25→    private readonly stripeService: StripeService,
    26→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    27→  ) {}
    28→
    29→  /**
    30→   * Create a Stripe Checkout Session for a payment.
    31→   * Generates a hosted payment page where users can complete their payment.
    32→   *
    33→   * @param userId - User ID (for ownership validation)
    34→   * @param paymentId - Payment entity ID
    35→   * @param savedMethodId - Optional Stripe PaymentMethod ID for quick checkout
    36→   * @returns Checkout session URL and ID
    37→   */
    38→  async createCheckoutSession(
    39→    userId: string,
    40→    paymentId: string,
    41→  ): Promise<{ url: string; sessionId: string }> {
    42→    return this.txHost.withTransaction(async () => {
    43→      const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);
    44→
    45→      // Load payment
    46→      const payment = await paymentRepository.findOne({
    47→        where: { id: paymentId },
    48→        relations: ['user'],
    49→      });
    50→
    51→      if (!payment) {
    52→        throw new NotFoundException('Payment not found');
    53→      }
    54→
    55→      // Validate payment ownership
    56→      if (payment.userId !== userId) {
    57→        throw new NotFoundException('Payment not found');
    58→      }
    59→
    60→      // Validate payment status
    61→      if (payment.status !== PaymentStatus.Created) {
    62→        throw new BadRequestException(
    63→          `Cannot create checkout session for payment in ${payment.status} status`,
    64→        );
    65→      }
    66→
    67→      // Validate payment hasn't expired
    68→      if (payment.expiresAt && payment.expiresAt < new Date()) {
    69→        throw new BadRequestException('Payment has expired');
    70→      }
    71→
    72→      // Get or create Stripe Customer
    73→      const stripe = this.stripeService.getClient();
    74→      const customerId = await this.stripeService.getOrCreateCustomer({
    75→        userId: payment.userId,
    76→        email: payment.user.email,
    77→        name: payment.user.fullName,
    78→      });
    79→
    80→      // Prepare checkout session parameters
    81→      const sessionParams: Stripe.Checkout.SessionCreateParams = {
    82→        mode: 'payment',
    83→        customer: customerId,
    84→        success_url: `${env.CORE_PUBLIC_URL}/payments/success?session_id={CHECKOUT_SESSION_ID}`,
    85→        cancel_url: `${env.CORE_PUBLIC_URL}/payments/cancel?payment_id=${payment.id}`,
    86→        payment_method_types: ['card', 'us_bank_account'],
    87→        line_items: [
    88→          {
    89→            price_data: {
    90→              currency: payment.currency.toLowerCase(),
    91→              product_data: {
    92→                name: `Payment - ${payment.purpose}`,
    93→                description: `Payment ID: ${payment.id}`,
    94→              },
    95→              unit_amount: payment.amountTotal,
    96→            },
    97→            quantity: 1,
    98→          },
    99→        ],
   100→        payment_intent_data: {
   101→          metadata: {
   102→            paymentId: payment.id,
   103→            userId: payment.userId,
   104→            purpose: payment.purpose,
   105→          },
   106→        },
   107→        metadata: {
   108→          paymentId: payment.id,
   109→          userId: payment.userId,
   110→          purpose: payment.purpose,
   111→        },
   112→        // Expire session after 30 minutes (or when payment expires)
   113→        expires_at: Math.floor(payment.expiresAt.getTime() / 1000),
   114→      };
   115→
   116→      // Create Checkout Session
   117→      const session = await stripe.checkout.sessions.create(sessionParams);
   118→
   119→      this.logger.log(
   120→        `Created Stripe Checkout Session: ${session.id} for payment: ${payment.id}`,
   121→      );
   122→
   123→      // Update payment with session reference and mark as PENDING
   124→      payment.status = PaymentStatus.Pending;
   125→      payment.providerRef = session.id;
   126→      await paymentRepository.save(payment);
   127→
   128→      return {
   129→        url: session.url!,
   130→        sessionId: session.id,
   131→      };
   132→    });
   133→  }
   134→}
