     1→import {
     2→  BadRequestException,
     3→  ConflictException,
     4→  Injectable,
     5→  NotFoundException,
     6→} from '@nestjs/common';
     7→import { TransactionHost } from '@nestjs-cls/transactional';
     8→
     9→import {
    10→  AuditLogEntity,
    11→  PaymentEntity,
    12→  PaymentLineItemEntity,
    13→  PaymentMethod,
    14→  PaymentProvider,
    15→  PaymentPurpose,
    16→  PaymentStatus,
    17→} from '@/db';
    18→import { TransactionalAdapterTypeOrm } from '@/modules/global';
    19→import { isValidCurrency, sumMinorUnits, toMinorUnits } from '@/common/money';
    20→import { getProviderFromMethod } from '@/common/payment-utils';
    21→import { CreatePaymentDto } from '@/api/app/payments/dtos/create-payment.dto';
    22→import { UpdatePaymentDto } from '../dtos/update-payment.dto';
    23→import { FeeCalculationService } from './fee-calculation.service';
    24→
    25→@Injectable()
    26→export class PaymentsService {
    27→  constructor(
    28→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    29→    private readonly feeCalculationService: FeeCalculationService,
    30→  ) {}
    31→
    32→  /**
    33→   * Create a new payment (deposit or fee).
    34→   *
    35→   * DEPOSIT: User adds funds to wallet. Processing fees are calculated and added.
    36→   * FEE: User pays service fees (buyback, extensions, etc.) using saved payment method.
    37→   *      For FEE payments, amountTotal should be provided directly (no fee calculation).
    38→   */
    39→  async create(userId: string, dto: CreatePaymentDto): Promise<PaymentEntity> {
    40→    return this.txHost.withTransaction(async () => {
    41→      const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);
    42→      const lineItemRepository = this.txHost.tx.getRepository(
    43→        PaymentLineItemEntity,
    44→      );
    45→      const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
    46→
    47→      // Default currency to USD
    48→      const currency = dto.currency || 'USD';
    49→
    50→      // Validate currency
    51→      if (!isValidCurrency(currency)) {
    52→        throw new BadRequestException('Invalid currency code');
    53→      }
    54→
    55→      // Check for existing payment with same idempotency key
    56→      // This a de-duplication mechanism to prevent duplicate payments
    57→      if (dto.idempotencyKey) {
    58→        const existingPayment = await paymentRepository.findOne({
    59→          where: {
    60→            userId,
    61→            idempotencyKey: dto.idempotencyKey,
    62→          },
    63→          relations: ['lineItems'],
    64→        });
    65→
    66→        if (existingPayment) {
    67→          // Return existing payment if found (idempotent behavior)
    68→          return existingPayment;
    69→        }
    70→      }
    71→
    72→      let amountSubtotal: number;
    73→      let feeAmount: number;
    74→      let taxAmount: number;
    75→      let amountTotal: number;
    76→      let method: PaymentMethod;
    77→      let provider: PaymentProvider;
    78→
    79→      if (dto.purpose === PaymentPurpose.Deposit) {
    80→        // DEPOSIT: Calculate fees based on wallet amount
    81→        if (!dto.walletAmount) {
    82→          throw new BadRequestException(
    83→            'walletAmount is required for DEPOSIT payments',
    84→          );
    85→        }
    86→
    87→        // Convert dollars to cents
    88→        const walletAmountCents = toMinorUnits(dto.walletAmount);
    89→
    90→        // Calculate Stripe fees using FeeCalculationService
    91→        const fees =
    92→          this.feeCalculationService.calculateDepositFees(walletAmountCents);
    93→
    94→        // Amounts for payment record
    95→        amountSubtotal = fees.walletAmount; // Amount that goes to wallet
    96→        feeAmount = fees.stripeFee; // Stripe processing fee
    97→        taxAmount = 0; // No VAT on deposits
    98→        amountTotal = sumMinorUnits([amountSubtotal, feeAmount, taxAmount]);
    99→
   100→        // Determine provider based on method (if provided)
   101→        // Method is optional for DEPOSIT - user selects at checkout
   102→        // Default to STRIPE_CARD if not provided
   103→        method = dto.method || PaymentMethod.StripeCard;
   104→        provider = getProviderFromMethod(method);
   105→      } else if (dto.purpose === PaymentPurpose.Fee) {
   106→        // FEE: Use provided amount directly (no fee calculation)
   107→        if (!dto.amountTotal) {
   108→          throw new BadRequestException(
   109→            'amountTotal is required for FEE payments',
   110→          );
   111→        }
   112→
   113→        // For FEE payments, amountTotal is the fee amount itself
   114→        amountTotal = toMinorUnits(dto.amountTotal);
   115→        amountSubtotal = amountTotal; // Fee amount is the subtotal
   116→        feeAmount = 0; // No additional processing fee for fee payments
   117→        taxAmount = dto.taxAmount ? toMinorUnits(dto.taxAmount) : 0;
   118→
   119→        // Method is required for FEE payments (must use saved payment method)
   120→        if (!dto.method) {
   121→          throw new BadRequestException('method is required for FEE payments');
   122→        }
   123→
   124→        // Validate method is PayPal for FEE payments (Stripe FEE not yet supported)
   125→        if (
   126→          dto.method !== PaymentMethod.PayPalAccount &&
   127→          dto.method !== PaymentMethod.PayPalBank
   128→        ) {
   129→          throw new BadRequestException(
   130→            'Only PayPal methods are supported for FEE payments',
   131→          );
   132→        }
   133→
   134→        method = dto.method;
   135→        provider = getProviderFromMethod(method);
   136→      } else {
   137→        throw new BadRequestException(
   138→          `Unsupported payment purpose: ${dto.purpose}`,
   139→        );
   140→      }
   141→
   142→      // Set expiry to 30 minutes from now
   143→      const expiresAt = new Date();
   144→      expiresAt.setMinutes(expiresAt.getMinutes() + 30);
   145→
   146→      // Create payment
   147→      const paymentData: Partial<PaymentEntity> = {
   148→        userId,
   149→        purpose: dto.purpose,
   150→        method,
   151→        provider,
   152→        amountSubtotal,
   153→        feeAmount,
   154→        taxAmount,
   155→        amountTotal,
   156→        currency: currency.toUpperCase(),
   157→        status: PaymentStatus.Created,
   158→        expiresAt,
   159→        metadata: dto.metadata || null,
   160→        idempotencyKey: dto.idempotencyKey || null,
   161→      };
   162→
   163→      const payment = await paymentRepository.save(paymentData);
   164→
   165→      // Create line items if provided
   166→      if (dto.lineItems?.length) {
   167→        const lineItems = dto.lineItems.map((item) => ({
   168→          paymentId: payment.id,
   169→          type: item.type,
   170→          amount: toMinorUnits(item.amount),
   171→          description: item.description || null,
   172→        }));
   173→
   174→        await lineItemRepository.save(lineItems);
   175→      }
   176→
   177→      // Create audit log
   178→      const auditData: Partial<AuditLogEntity> = {
   179→        actorUserId: userId,
   180→        entity: 'payment',
   181→        entityId: payment.id,
   182→        action: 'created',
   183→        metadata: {
   184→          purpose: dto.purpose,
   185→          amountTotal,
   186→          amountSubtotal,
   187→          feeAmount,
   188→          taxAmount,
   189→          currency,
   190→          method,
   191→        },
   192→      };
   193→
   194→      await auditRepository.save(auditData);
   195→
   196→      // Return payment with line items
   197→      const result = await paymentRepository.findOne({
   198→        where: { id: payment.id },
   199→        relations: ['lineItems'],
   200→      });
   201→
   202→      if (!result) {
   203→        throw new Error('Payment not found after creation');
   204→      }
   205→
   206→      return result;
   207→    });
   208→  }
   209→
   210→  async getOne(userId: string, paymentId: string): Promise<PaymentEntity> {
   211→    const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);
   212→
   213→    const payment = await paymentRepository.findOne({
   214→      where: { id: paymentId, userId },
   215→      relations: ['lineItems'],
   216→    });
   217→
   218→    if (!payment) {
   219→      throw new NotFoundException('Payment not found');
   220→    }
   221→
   222→    return payment;
   223→  }
   224→
   225→  async getMany(userId: string): Promise<PaymentEntity[]> {
   226→    const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);
   227→
   228→    return paymentRepository.find({
