   235→  async update(
   236→    userId: string,
   237→    paymentId: string,
   238→    dto: UpdatePaymentDto,
   239→  ): Promise<PaymentEntity> {
   240→    return this.txHost.withTransaction(async () => {
   241→      const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);
   242→      const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
   243→
   244→      const payment = await paymentRepository.findOne({
   245→        where: { id: paymentId, userId },
   246→      });
   247→
   248→      if (!payment) {
   249→        throw new NotFoundException('Payment not found');
   250→      }
   251→
   252→      // Only allow updates when payment is in CREATED status
   253→      if (payment.status !== PaymentStatus.Created) {
   254→        throw new ConflictException(
   255→          `Cannot update payment in ${payment.status} status`,
   256→        );
   257→      }
   258→
   259→      const oldValues = { ...payment };
   260→      const updatedPayment = { ...payment };
   261→
   262→      // Update allowed fields
   263→      if (dto.method !== undefined) {
   264→        const newMethod: PaymentMethod = dto.method;
   265→        updatedPayment.method = newMethod;
   266→        updatedPayment.provider = getProviderFromMethod(newMethod);
   267→      }
   268→
   269→      if (dto.metadata !== undefined) {
   270→        updatedPayment.metadata = dto.metadata;
   271→      }
   272→
   273→      await paymentRepository.save(updatedPayment);
   274→
   275→      // Create audit log with diff
   276→      const diff: Record<string, any> = {};
   277→      if (dto.method !== undefined && dto.method !== oldValues.method) {
   278→        diff.method = { from: oldValues.method, to: dto.method };
   279→      }
   280→      if (dto.metadata !== undefined) {
   281→        diff.metadata = { from: oldValues.metadata, to: dto.metadata };
   282→      }
   283→
   284→      if (Object.keys(diff).length > 0) {
   285→        await auditRepository.save({
   286→          actorUserId: userId,
   287→          entity: 'payment',
   288→          entityId: paymentId,
   289→          action: 'updated',
   290→          diff,
   291→        });
   292→      }
   293→
   294→      const result = await paymentRepository.findOne({
   295→        where: { id: paymentId },
   296→        relations: ['lineItems'],
   297→      });
   298→
   299→      if (!result) {
   300→        throw new Error('Payment not found after update');
   301→      }
   302→
   303→      return result;
   304→    });
   305→  }
