   307→  async delete(userId: string, paymentId: string): Promise<void> {
   308→    return this.txHost.withTransaction(async () => {
   309→      const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);
   310→      const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
   311→
   312→      const payment = await paymentRepository.findOne({
   313→        where: { id: paymentId, userId },
   314→      });
   315→
   316→      if (!payment) {
   317→        throw new NotFoundException('Payment not found');
   318→      }
   319→
   320→      // Only allow deletion when payment is CREATED or PENDING and has no provider reference
   321→      if (
   322→        ![PaymentStatus.Created, PaymentStatus.Pending].includes(
   323→          payment.status,
   324→        ) ||
   325→        payment.providerRef
   326→      ) {
   327→        throw new ConflictException(
   328→          'Cannot delete payment that has been processed or has provider reference',
   329→        );
   330→      }
   331→
   332→      // Soft delete the payment
   333→      await paymentRepository.softDelete({ id: paymentId });
   334→
   335→      // Create audit log
   336→      await auditRepository.save({
   337→        actorUserId: userId,
   338→        entity: 'payment',
   339→        entityId: paymentId,
   340→        action: 'deleted',
   341→        metadata: {
   342→          status: payment.status,
   343→          amountTotal: payment.amountTotal,
   344→          currency: payment.currency,
   345→        },
   346→      });
   347→    });
   348→  }
