   350→  /**
   351→   * Expire payments that are past their expiry time and in CREATED or PENDING status
   352→   */
   353→  async expireStalePayments(): Promise<number> {
   354→    return this.txHost.withTransaction(async () => {
   355→      const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);
   356→      const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
   357→
   358→      const now = new Date();
   359→
   360→      // Find payments to expire
   361→      const paymentsToExpire = await paymentRepository
   362→        .createQueryBuilder('payment')
   363→        .where('payment.status IN (:...statuses)', {
   364→          statuses: [PaymentStatus.Created, PaymentStatus.Pending],
   365→        })
   366→        .andWhere('payment.expiresAt < :now', { now })
   367→        .getMany();
   368→
   369→      if (paymentsToExpire.length === 0) {
   370→        return 0;
   371→      }
   372→
   373→      // Update payments to expired status
   374→      const paymentIds = paymentsToExpire.map((p) => p.id);
   375→      await paymentRepository
   376→        .createQueryBuilder()
   377→        .update(PaymentEntity)
   378→        .set({ status: PaymentStatus.Expired })
   379→        .where('id IN (:...ids)', { ids: paymentIds })
   380→        .execute();
   381→
   382→      // Create audit logs
   383→      const auditLogs = paymentsToExpire.map((payment) => ({
   384→        entity: 'payment',
   385→        entityId: payment.id,
   386→        action: 'expired',
   387→        metadata: {
   388→          previousStatus: payment.status,
   389→          expiresAt: payment.expiresAt,
   390→          expiredAt: now,
   391→        },
   392→      }));
   393→
   394→      await auditRepository.save(auditLogs);
   395→
   396→      return paymentsToExpire.length;
   397→    });
   398→  }
