     1→import {
     2→  BadRequestException,
     3→  Injectable,
     4→  Logger,
     5→  NotFoundException,
     6→} from '@nestjs/common';
     7→import { TransactionHost } from '@nestjs-cls/transactional';
     8→
     9→import { SavedStripeMethodEntity, StripeMethodType, WalletEntity } from '@/db';
    10→import { TransactionalAdapterTypeOrm } from '@/modules/global';
    11→import { StripeService } from '@/modules/stripe';
    12→
    13→interface CreateStripeMethodData {
    14→  setupIntentId: string;
    15→  nickname?: string;
    16→  setAsDefault?: boolean;
    17→}
    18→
    19→interface UpdateStripeMethodData {
    20→  nickname?: string;
    21→  setAsDefault?: boolean;
    22→}
    23→
    24→@Injectable()
    25→export class StripeMethodsService {
    26→  private readonly logger = new Logger(StripeMethodsService.name);
    27→
    28→  constructor(
    29→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    30→    private readonly stripeService: StripeService,
    31→  ) {}
    32→
    33→  /**
    34→   * Create Stripe SetupIntent for payment method tokenization.
    35→   * Frontend uses clientSecret with Stripe.js to collect card/bank details.
    36→   */
    37→  async createSetupIntent(
    38→    userId: string,
    39→  ): Promise<{ clientSecret: string; setupIntentId: string }> {
    40→    const userRepository = this.txHost.tx.getRepository(WalletEntity);
    41→
    42→    const wallet = await userRepository.findOne({
    43→      where: { userId },
    44→      relations: ['user'],
    45→    });
    46→
    47→    if (!wallet?.user) {
    48→      throw new NotFoundException('User not found');
    49→    }
    50→
    51→    // Get or create Stripe customer with user details
    52→    const stripeCustomerId = await this.stripeService.getOrCreateCustomer({
    53→      userId,
    54→      email: wallet.user.email,
    55→      name: wallet.user.fullName,
    56→    });
    57→
    58→    // Create SetupIntent
    59→    const setupIntent =
    60→      await this.stripeService.createSetupIntent(stripeCustomerId);
    61→
    62→    if (!setupIntent.client_secret) {
    63→      throw new BadRequestException('Failed to create SetupIntent');
    64→    }
    65→
    66→    this.logger.log(`Created SetupIntent ${setupIntent.id} for user ${userId}`);
    67→
    68→    return {
    69→      clientSecret: setupIntent.client_secret,
    70→      setupIntentId: setupIntent.id,
    71→    };
    72→  }
    73→
    74→  /**
    75→   * Save a tokenized Stripe payment method after SetupIntent completion.
    76→   * Retrieves payment method details from Stripe and stores references.
    77→   */
    78→  async create(
    79→    userId: string,
    80→    data: CreateStripeMethodData,
    81→  ): Promise<SavedStripeMethodEntity> {
    82→    return this.txHost.withTransaction(async () => {
    83→      const repository = this.txHost.tx.getRepository(SavedStripeMethodEntity);
    84→      const walletRepository = this.txHost.tx.getRepository(WalletEntity);
    85→      const stripe = this.stripeService.getClient();
    86→
    87→      // 1. Retrieve SetupIntent from Stripe to get payment_method
    88→      const setupIntent = await stripe.setupIntents.retrieve(
    89→        data.setupIntentId,
    90→      );
    91→
    92→      if (setupIntent.status !== 'succeeded') {
    93→        throw new BadRequestException(
    94→          'SetupIntent not completed. Please complete payment method setup first.',
    95→        );
    96→      }
    97→
    98→      const paymentMethodId = setupIntent.payment_method;
    99→
   100→      if (!paymentMethodId || typeof paymentMethodId !== 'string') {
   101→        throw new BadRequestException(
   102→          'No payment method attached to SetupIntent',
   103→        );
   104→      }
   105→
   106→      // 2. Retrieve PaymentMethod details from Stripe
   107→      const paymentMethod =
   108→        await this.stripeService.retrievePaymentMethod(paymentMethodId);
   109→
   110→      // 3. Get customer ID from payment method (already attached during SetupIntent)
   111→      const stripeCustomerId =
   112→        typeof paymentMethod.customer === 'string'
   113→          ? paymentMethod.customer
   114→          : paymentMethod.customer?.id;
   115→
   116→      if (!stripeCustomerId) {
   117→        throw new BadRequestException(
   118→          'Payment method not attached to a customer',
   119→        );
   120→      }
   121→
   122→      // 4. Get wallet for this user
   123→      const wallet = await walletRepository.findOne({
   124→        where: { userId },
   125→      });
   126→
   127→      if (!wallet) {
   128→        throw new NotFoundException('Wallet not found for user');
   129→      }
   130→
   131→      // 5. Check if payment method already exists (idempotency)
   132→      const existingMethod = await repository.findOne({
   133→        where: {
   134→          walletId: wallet.id,
   135→          stripePaymentMethodId: paymentMethodId,
   136→        },
   137→      });
   138→
   139→      if (existingMethod) {
   140→        return existingMethod;
   141→      }
   142→
   143→      // 6. Handle default setting
   144→      if (data.setAsDefault) {
   145→        await repository
   146→          .createQueryBuilder()
   147→          .update(SavedStripeMethodEntity)
   148→          .set({ isDefault: false })
   149→          .where('wallet_id = :walletId', { walletId: wallet.id })
   150→          .execute();
   151→      }
   152→
   153→      // 7. Determine method type and extract details
   154→      let methodType: StripeMethodType;
   155→      let last4: string;
   156→      let brand: string;
   157→      let expiryMonth: number | null = null;
   158→      let expiryYear: number | null = null;
   159→
   160→      if (paymentMethod.type === 'card' && paymentMethod.card) {
   161→        methodType = StripeMethodType.Card;
   162→        last4 = paymentMethod.card.last4;
   163→        brand = paymentMethod.card.brand;
   164→        expiryMonth = paymentMethod.card.exp_month;
   165→        expiryYear = paymentMethod.card.exp_year;
   166→      } else if (
   167→        paymentMethod.type === 'us_bank_account' &&
   168→        paymentMethod.us_bank_account
   169→      ) {
   170→        methodType = StripeMethodType.BankAccount;
   171→        last4 = paymentMethod.us_bank_account.last4 || '****';
   172→        brand = paymentMethod.us_bank_account.bank_name || 'Bank Account';
   173→      } else {
   174→        throw new BadRequestException(
   175→          `Unsupported payment method type: ${paymentMethod.type}`,
   176→        );
   177→      }
   178→
   179→      // 8. Save to database
   180→      const savedMethod = await repository.save({
   181→        walletId: wallet.id,
   182→        stripePaymentMethodId: paymentMethodId,
   183→        stripeCustomerId,
   184→        type: methodType,
   185→        last4,
   186→        brand,
   187→        expiryMonth,
   188→        expiryYear,
   189→        isDefault: data.setAsDefault || false,
   190→        nickname: data.nickname || null,
   191→      });
   192→
   193→      this.logger.log(
   194→        `Saved payment method ${savedMethod.id} for user ${userId}`,
   195→      );
   196→
   197→      return savedMethod;
   198→    });
   199→  }
   200→
   201→  /**
   202→   * Get all saved Stripe payment methods for a user.
   203→   * Ordered by default first, then by creation date.
   204→   */
   205→  async getMany(userId: string): Promise<SavedStripeMethodEntity[]> {
   206→    const repository = this.txHost.tx.getRepository(SavedStripeMethodEntity);
   207→
   208→    return repository.find({
   209→      where: { wallet: { userId } },
   210→      order: {
   211→        isDefault: 'DESC',
   212→        createdAt: 'DESC',
   213→      },
   214→    });
   215→  }
   216→
   217→  /**
   218→   * Get a single saved Stripe payment method by ID.
   219→   */
   220→  async getOne(
   221→    userId: string,
   222→    methodId: string,
   223→  ): Promise<SavedStripeMethodEntity> {
   224→    const repository = this.txHost.tx.getRepository(SavedStripeMethodEntity);
   225→
   226→    const method = await repository.findOne({
   227→      where: { id: methodId, wallet: { userId } },
   228→    });
   229→
   230→    if (!method) {
   231→      throw new NotFoundException('Payment method not found');
   232→    }
   233→
   234→    return method;
   235→  }
   236→
   237→  /**
   238→   * Update a saved Stripe payment method (nickname, default status).
   239→   */
   240→  async update(
   241→    userId: string,
   242→    methodId: string,
   243→    data: UpdateStripeMethodData,
   244→  ): Promise<SavedStripeMethodEntity> {
   245→    return this.txHost.withTransaction(async () => {
   246→      const repository = this.txHost.tx.getRepository(SavedStripeMethodEntity);
   247→
   248→      const method = await repository.findOne({
   249→        where: { id: methodId, wallet: { userId } },
   250→      });
   251→
   252→      if (!method) {
   253→        throw new NotFoundException('Payment method not found');
   254→      }
   255→
   256→      // Handle default setting (atomic update)
   257→      if (data.setAsDefault) {
   258→        // Unset all other defaults for this user
   259→        await repository
   260→          .createQueryBuilder()
   261→          .update(SavedStripeMethodEntity)
   262→          .set({ isDefault: false })
   263→          .where('wallet_id = :walletId', { walletId: method.walletId })
   264→          .andWhere('id != :methodId', { methodId })
   265→          .execute();
   266→
   267→        method.isDefault = true;
   268→      }
   269→
   270→      // Update nickname if provided
   271→      if (data.nickname !== undefined) {
   272→        method.nickname = data.nickname;
   273→      }
   274→
   275→      await repository.save(method);
   276→
   277→      const result = await repository.findOne({
   278→        where: { id: methodId },
   279→      });
   280→
   281→      if (!result) {
   282→        throw new Error('Payment method not found after update');
   283→      }
   284→
   285→      return result;
   286→    });
   287→  }
   288→
   289→  /**
   290→   * Delete (soft delete) a saved Stripe payment method.
   291→   * Also detaches from Stripe Customer.
   292→   */
   293→  async delete(userId: string, methodId: string): Promise<void> {
   294→    return this.txHost.withTransaction(async () => {
   295→      const repository = this.txHost.tx.getRepository(SavedStripeMethodEntity);
   296→
   297→      const method = await repository.findOne({
   298→        where: { id: methodId, wallet: { userId } },
   299→      });
   300→
   301→      if (!method) {
   302→        throw new NotFoundException('Payment method not found');
   303→      }
   304→
   305→      // Detach from Stripe Customer
   306→      try {
   307→        await this.stripeService.detachPaymentMethod(
   308→          method.stripePaymentMethodId,
   309→        );
   310→        this.logger.log(
   311→          `Detached payment method ${method.stripePaymentMethodId} from Stripe`,
   312→        );
   313→      } catch (error) {
   314→        // Log error but don't fail the deletion
   315→        // The payment method might already be detached or deleted in Stripe
   316→        this.logger.warn(
   317→          `Failed to detach payment method from Stripe: ${error}`,
   318→        );
   319→      }
   320→
   321→      // Soft delete from database
   322→      await repository.softDelete({ id: methodId });
   323→
   324→      this.logger.log(`Deleted payment method ${methodId} for user ${userId}`);
   325→
   326→      // If this was the default, promote another method
   327→      if (method.isDefault) {
   328→        const nextMethod = await repository.findOne({
   329→          where: { wallet: { userId } },
   330→          order: { createdAt: 'DESC' },
   331→        });
   332→
   333→        if (nextMethod) {
   334→          nextMethod.isDefault = true;
   335→          await repository.save(nextMethod);
   336→          this.logger.log(
   337→            `Promoted payment method ${nextMethod.id} to default`,
   338→          );
   339→        }
   340→      }
   341→    });
   342→  }
   343→}
