    56→  /**
    57→   * Stripe webhook endpoint.
    58→   * Receives events from Stripe and processes them.
    59→   *
    60→   * IMPORTANT: This endpoint requires raw body for signature verification.
    61→   * Fastify/NestJS must be configured to provide rawBody.
    62→   */
    63→  @Post()
    64→  async handleWebhook(
    65→    @Req() request: RawBodyRequest<FastifyRequest>,
    66→    @Headers('stripe-signature') signature: string,
    67→  ): Promise<{ received: boolean }> {
    68→    if (!signature) {
    69→      this.logger.error('Missing stripe-signature header');
    70→      throw new BadRequestException('Missing stripe-signature header');
    71→    }
    72→
    73→    const webhookSecret = this.config.get<string>('STRIPE_WEBHOOK_SECRET')!;
    74→    if (!webhookSecret) {
    75→      this.logger.error('STRIPE_WEBHOOK_SECRET not configured');
    76→      throw new BadRequestException('Webhook secret not configured');
    77→    }
    78→
    79→    // Get raw body for signature verification
    80→    const rawBody = request.rawBody;
    81→    if (!rawBody) {
    82→      this.logger.error('Missing raw body for signature verification');
    83→      throw new BadRequestException('Missing raw body');
    84→    }
    85→
    86→    let event: Stripe.Event;
    87→
    88→    try {
    89→      // Verify webhook signature
    90→      event = this.stripeService.constructWebhookEvent(
    91→        rawBody,
    92→        signature,
    93→        webhookSecret,
    94→      );
    95→
    96→      this.logger.log(
    97→        `✓ Verified webhook signature for event: ${event.id} (${event.type})`,
    98→      );
    99→    } catch (err) {
   100→      const error = err as Error;
   101→      this.logger.error(
   102→        `✗ Webhook signature verification failed: ${error.message}`,
   103→      );
   104→      throw new BadRequestException(`Webhook signature verification failed`);
   105→    }
   106→
   107→    // Process the event based on type
   108→    try {
   109→      await this.processEvent(event);
   110→      return { received: true };
   111→    } catch (error) {
   112→      const err = error as Error;
   113→      this.logger.error(
   114→        `Error processing webhook event ${event.id}: ${err.message}`,
   115→        err.stack,
   116→      );
   117→      throw new BadRequestException('Webhook processing failed');
   118→    }
   119→  }
