   121→  /**
   122→   * Process a verified Stripe event.
   123→   * Routes to appropriate handler based on event type.
   124→   */
   125→  private async processEvent(event: Stripe.Event): Promise<void> {
   126→    this.logger.log(`Processing event: ${event.type} (${event.id})`);
   127→
   128→    // Check idempotency - skip if already processed
   129→    const isNewEvent = await this.stripeWebhookService.storeEvent(event);
   130→    if (!isNewEvent) {
   131→      this.logger.log(`Event ${event.id} already processed, skipping`);
   132→      return;
   133→    }
   134→
   135→    // Process the event
   136→    try {
   137→      await this.handleEventByType(event);
   138→
   139→      // Mark as processed
   140→      await this.stripeWebhookService.markEventProcessed(event.id);
   141→      this.logger.log(`✓ Successfully processed event: ${event.id}`);
   142→    } catch (error) {
   143→      const err = error as Error;
   144→      this.logger.error(
   145→        `✗ Error processing event ${event.id}: ${err.message}`,
   146→        err.stack,
   147→      );
   148→      throw error; // Re-throw to return error to Stripe
   149→    }
   150→  }
