   163→        break;
   164→
   165→      case 'payment_intent.succeeded':
   166→        await this.handlePaymentIntentSucceeded(event.data.object);
   167→        break;
   168→
   169→      case 'payment_intent.payment_failed':
   170→        await this.handlePaymentIntentFailed(event.data.object);
   171→        break;
   172→
   173→      case 'payment_intent.canceled':
   174→        await this.handlePaymentIntentCanceled(event.data.object);
   175→        break;
   176→
   177→      case 'charge.refunded':
   178→        await this.handleChargeRefunded(event.data.object);
   179→        break;
   180→
   181→      case 'identity.verification_session.verified':
   182→        await this.handleVerificationSessionVerified(event.data.object);
   183→        break;
   184→
   185→      case 'identity.verification_session.requires_input':
   186→        await this.handleVerificationSessionRequiresInput(event.data.object);
   187→        break;
   188→
   189→      case 'identity.verification_session.processing':
   190→        await this.handleVerificationSessionProcessing(event.data.object);
   191→        break;
   192→
   193→      case 'identity.verification_session.canceled':
