   202→  /**
   203→   * Handle checkout.session.completed event.
   204→   * Called when user successfully completes payment on Stripe checkout page.
   205→   */
   206→  private async handleCheckoutSessionCompleted(
   207→    session: Stripe.Checkout.Session,
   208→  ): Promise<void> {
   209→    const paymentIntentId =
   210→      typeof session.payment_intent === 'string'
   211→        ? session.payment_intent
   212→        : session.payment_intent?.id || 'unknown';
   213→
   214→    this.logger.log(
   215→      `Checkout session completed: ${session.id} (payment_intent: ${paymentIntentId})`,
   216→    );
   217→
   218→    // Extract paymentId from metadata
   219→    const paymentId = session.metadata?.paymentId;
   220→    if (!paymentId) {
   221→      this.logger.error(
   222→        `No paymentId in checkout session metadata: ${session.id}`,
   223→      );
   224→      throw new BadRequestException('Missing paymentId in session metadata');
   225→    }
   226→
   227→    // Get payment
   228→    const payment = await this.paymentsService.findOneById(paymentId);
   229→    if (!payment) {
   230→      this.logger.error(`Payment not found: ${paymentId}`);
   231→      throw new BadRequestException('Payment not found');
   232→    }
   233→
   234→    // Update payment status to SUCCEEDED
   235→    await this.paymentsService.updateStatus(paymentId, PaymentStatus.Succeeded);
   236→
   237→    this.logger.log(
   238→      `✓ Payment ${paymentId} marked as SUCCEEDED (session: ${session.id})`,
   239→    );
   240→
   241→    // Store Stripe customer ID as fallback (defensive programming)
   242→    const customerId =
   243→      typeof session.customer === 'string'
   244→        ? session.customer
   245→        : session.customer?.id;
   246→
   247→    if (customerId) {
   248→      const walletRepository = this.dataSource.getRepository(WalletEntity);
   249→
   250→      const wallet = await walletRepository.findOne({
   251→        where: { userId: payment.userId },
   252→        select: ['id', 'stripeCustomerId'],
   253→      });
   254→
   255→      // Only update if not already set (prevent unnecessary writes)
   256→      if (wallet && !wallet.stripeCustomerId) {
   257→        await walletRepository.update(
   258→          { id: wallet.id },
   259→          { stripeCustomerId: customerId },
   260→        );
   261→        this.logger.log(
   262→          `✓ Stored Stripe customer ID ${customerId} for user ${payment.userId} (via webhook fallback)`,
   263→        );
   264→      }
   265→    }
   266→
   267→    // Post deposit to ledger
   268→    // Note: Only DEPOSIT purpose is supported. All Stripe payments are deposits.
   269→    if (payment.purpose !== PaymentPurpose.Deposit) {
