   271→        `⚠️  Unexpected payment purpose: ${payment.purpose} (payment: ${paymentId})`,
   272→      );
   273→      throw new BadRequestException(
   274→        `Only DEPOSIT purpose is supported, got: ${payment.purpose}`,
   275→      );
   276→    }
   277→
   278→    await this.postDepositToLedger(payment);
   279→  }
