     1→import { PaymentMethod, PaymentProvider } from '@/db';
     2→
     3→/**
     4→ * Determines the payment provider based on the payment method.
     5→ * Stripe handles card and bank, PayPal handles PayPal methods, Crypto.com Pay, NOWPayments, and legacy crypto handle crypto transactions.
     6→ */
     7→export function getProviderFromMethod(method: PaymentMethod): PaymentProvider {
     8→  if (method.startsWith('STRIPE_')) {
     9→    return PaymentProvider.Stripe;
    10→  }
    11→
    12→  if (method.startsWith('PAYPAL_')) {
    13→    return PaymentProvider.PayPal;
    14→  }
    15→
    16→  if (method === PaymentMethod.CryptoPayAccount) {
    17→    return PaymentProvider.CryptoPay;
    18→  }
    19→
    20→  if (method === PaymentMethod.NowPaymentsCrypto) {
    21→    return PaymentProvider.NowPayments;
    22→  }
    23→
    24→  return PaymentProvider.Crypto;
    25→}
