     7→/**
     8→ * Stripe Identity Service
     9→ *
    10→ * Extends StripeService with Identity API methods for KYC verification.
    11→ * Handles creation and management of Stripe Identity verification sessions.
    12→ */
    13→@Injectable()
    14→export class StripeIdentityService {
    15→  private readonly logger = new Logger(StripeIdentityService.name);
    16→
    17→  constructor(private readonly stripeService: StripeService) {}
    18→
    19→  /**
    20→   * Create a Stripe Identity verification session.
    21→   * Used to initiate document verification with selfie matching.
    22→   *
    23→   * @param userId - Internal user ID (stored in metadata)
    24→   * @param returnUrl - URL to redirect user after verification completes
    25→   * @returns Verification session with client_secret for frontend
    26→   */
    27→  async createVerificationSession(
    28→    userId: string,
    29→    returnUrl: string,
    30→  ): Promise<Stripe.Identity.VerificationSession> {
    31→    const stripe = this.stripeService.getClient();
    32→
    33→    const session = await stripe.identity.verificationSessions.create({
    34→      type: 'document',
    35→      metadata: { userId },
    36→      return_url: returnUrl,
    37→      options: {
    38→        document: {
    39→          allowed_types: ['driving_license', 'id_card', 'passport'],
    40→        },
    41→      },
    42→    });
    43→
    44→    this.logger.log(
    45→      `Created verification session: ${session.id} for user: ${userId}`,
    46→    );
    47→
    48→    return session;
    49→  }
    50→
    51→  /**
    52→   * Retrieve a verification session from Stripe.
    53→   *
    54→   * @param sessionId - Stripe verification session ID
    55→   * @returns Verification session with current status and details
    56→   */
    57→  async retrieveVerificationSession(
    58→    sessionId: string,
    59→  ): Promise<Stripe.Identity.VerificationSession> {
    60→    const stripe = this.stripeService.getClient();
    61→
    62→    const session =
    63→      await stripe.identity.verificationSessions.retrieve(sessionId);
    64→
    65→    this.logger.log(`Retrieved verification session: ${sessionId}`);
    66→
    67→    return session;
    68→  }
    69→
    70→  /**
    71→   * Cancel an in-progress verification session.
    72→   *
    73→   * @param sessionId - Stripe verification session ID
    74→   * @returns Cancelled verification session
    75→   */
    76→  async cancelVerificationSession(
    77→    sessionId: string,
    78→  ): Promise<Stripe.Identity.VerificationSession> {
    79→    const stripe = this.stripeService.getClient();
    80→
    81→    const session =
    82→      await stripe.identity.verificationSessions.cancel(sessionId);
    83→
    84→    this.logger.log(`Cancelled verification session: ${sessionId}`);
    85→
    86→    return session;
    87→  }
    88→}
