     5→/**
     6→ * FeeCalculationService
     7→ *
     8→ * Centralized service for all fee calculations to prevent FE manipulation
     9→ * and ensure consistent, precise financial calculations across the platform.
    10→ *
    11→ * Key principles:
    12→ * - All amounts in cents (integers)
    13→ * - Use Decimal.js for precise calculations
    14→ * - Round charges UP (ceil), credits DOWN (floor)
    15→ * - Validate all inputs
    16→ */
    17→@Injectable()
    18→export class FeeCalculationService {
    19→  constructor(private readonly config: ConfigService) {}
    20→  /**
    21→   * Calculate fees for a deposit/top-up transaction
    22→   *
    23→   * Stripe charges: 2.9% + $0.30 per card transaction
    24→   * This fee is passed to the user on top of their wallet amount.
    25→   *
    26→   * @param walletAmountCents - Amount user wants in their wallet (in cents)
    27→   * @returns Fee breakdown with wallet amount, Stripe fee, and total charge
    28→   *
    29→   * @example
    30→   * calculateDepositFees(150000) // $1500
    31→   * // Returns: { walletAmount: 150000, stripeFee: 4380, total: 154380 }
    32→   * // User pays $1543.80 to get $1500.00 in wallet
    33→   */
    34→  calculateDepositFees(walletAmountCents: number): {
    35→    walletAmount: number;
    36→    stripeFee: number;
    37→    total: number;
    38→  } {
    39→    // Validation
    40→    if (!Number.isInteger(walletAmountCents) || walletAmountCents < 1) {
    41→      throw new Error('walletAmountCents must be a positive integer (cents)');
    42→    }
    43→
    44→    const minDepositCents = this.config.get<number>(
    45→      'MIN_DEPOSIT_AMOUNT_CENTS',
    46→    )!;
    47→    if (walletAmountCents < minDepositCents) {
    48→      throw new Error(
    49→        `Deposit amount must be at least ${minDepositCents} cents`,
    50→      );
    51→    }
    52→
    53→    // Calculate Stripe fee: (amount * percent) + fixed
    54→    const amount = new Decimal(walletAmountCents);
    55→    const feePercent = new Decimal(
    56→      this.config.get<number>('STRIPE_CARD_FEE_PERCENT')!,
    57→    ).div(100);
    58→    const feeFixed = new Decimal(
    59→      this.config.get<number>('STRIPE_CARD_FEE_FIXED_CENTS')!,
    60→    );
    61→
    62→    const stripeFee = amount.mul(feePercent).plus(feeFixed);
    63→
    64→    // Round UP (charge user more rather than less)
    65→    const stripeFeeRounded = stripeFee.ceil().toNumber();
    66→
    67→    // Total charge = wallet amount + stripe fee
    68→    const total = walletAmountCents + stripeFeeRounded;
    69→
    70→    return {
    71→      walletAmount: walletAmountCents,
    72→      stripeFee: stripeFeeRounded,
    73→      total,
    74→    };
    75→  }
    76→
    77→  /**
    78→   * Calculate minimum top-up amount needed to cover shortfall
    79→   *
    80→   * Returns the exact shortfall amount without any payment method fees.
    81→   * Fees will be calculated at payment time based on the selected payment method.
    82→   *
    83→   * @param shortfallCents - Amount user is short (in cents)
    84→   * @returns Shortfall amount (payment method agnostic)
    85→   *
    86→   * @example
    87→   * calculateTopUpRequired(167400) // User needs $1674
    88→   * // Returns: 167400 ($1674.00 exact shortfall)
    89→   * // Payment fees will be added based on chosen payment method (Stripe, crypto, etc.)
    90→   */
    91→  calculateTopUpRequired(shortfallCents: number): number {
    92→    // Validation
    93→    if (!Number.isInteger(shortfallCents) || shortfallCents < 1) {
    94→      throw new Error('shortfallCents must be a positive integer (cents)');
    95→    }
    96→
    97→    // Return exact shortfall - no payment method assumptions
    98→    return shortfallCents;
    99→  }
